import React, { useState } from 'react';

const TIER_EMOJI = {
  light:  '😌',
  medium: '🤔',
  urgent: '😬',
  crisis: '😱',
};

export default function NudgePopup({ nudge, onPause, onSkip }) {
  const [flashing, setFlashing] = useState(false);

  const ctx         = nudge?.context ?? {};
  const spendPct    = ctx.spend_pct    ?? ctx.percent_spent ?? 0;
  const masterAmt   = ctx.master_monthly ?? ctx.budget_amount ?? 0;
  const spentAmt    = ctx.spent_amount ?? Math.round((masterAmt * spendPct) / 100);
  const tierEmoji   = TIER_EMOJI[nudge?.tier] ?? '🤔';

  const handlePause = () => {
    setFlashing(true);
    // Let the green flash render (0.2s) then fire parent handler
    setTimeout(() => onPause(), 200);
  };

  return (
    <>
      {/* Backdrop */}
      <div
        className="fade-in"
        onClick={onSkip}
        style={{
          position: 'fixed',
          inset: 0,
          background: 'rgba(0,0,0,0.6)',
          zIndex: 50,
        }}
      />

      {/* Bottom sheet */}
      <div
        className="slide-up"
        style={{
          position: 'fixed',
          bottom: 0,
          left: 0,
          right: 0,
          borderRadius: '24px 24px 0 0',
          background: 'var(--bg-secondary)',
          borderTop: '1px solid rgba(255,255,255,0.1)',
          backdropFilter: 'blur(20px)',
          WebkitBackdropFilter: 'blur(20px)',
          padding: '0 20px 40px',
          maxHeight: '85vh',
          overflowY: 'auto',
          zIndex: 51,
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Drag pill */}
        <div
          style={{
            width: 36,
            height: 4,
            background: 'rgba(255,255,255,0.3)',
            borderRadius: 2,
            margin: '12px auto 20px',
          }}
        />

        {/* Tag chip */}
        <div style={{ display: 'flex', justifyContent: 'center', marginBottom: 16 }}>
          <span
            style={{
              display: 'inline-flex',
              alignItems: 'center',
              background: 'var(--accent-muted)',
              border: '1px solid rgba(var(--accent-rgb, 255,179,71), 0.3)',
              borderRadius: 20,
              padding: '4px 12px',
              fontSize: 12,
              color: 'var(--accent)',
              fontWeight: 500,
            }}
          >
            {nudge?.tag ?? '⚡ SpendSense Check'}
          </span>
        </div>

        {/* Tier emoji */}
        <p style={{ fontSize: 40, textAlign: 'center', marginBottom: 12, lineHeight: 1 }}>
          {tierEmoji}
        </p>

        {/* Title */}
        <p
          style={{
            fontSize: 16,
            fontWeight: 500,
            color: '#FFFFFF',
            textAlign: 'center',
            marginBottom: 8,
            lineHeight: 1.4,
          }}
        >
          {nudge?.title ?? 'Hold on a second...'}
        </p>

        {/* Body */}
        <p
          style={{
            fontSize: 12,
            color: 'var(--text-muted)',
            textAlign: 'center',
            lineHeight: 1.7,
            marginBottom: 20,
            padding: '0 8px',
          }}
        >
          {nudge?.body ?? nudge?.message ?? 'SpendSense wants you to pause before this purchase.'}
        </p>

        {/* Context block */}
        <div className="glass-card" style={{ padding: 12, marginBottom: 20 }}>
          <div
            style={{
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              marginBottom: 8,
            }}
          >
            <span style={{ fontSize: 12, color: 'var(--text-muted)' }}>
              ₹{Math.round(spentAmt).toLocaleString('en-IN')} of{' '}
              ₹{Math.round(masterAmt).toLocaleString('en-IN')}
            </span>
            <span style={{ fontSize: 12, color: 'var(--accent)', fontWeight: 500 }}>
              {Math.round(spendPct)}% this month
            </span>
          </div>

          {/* Progress bar */}
          <div
            style={{
              height: 4,
              borderRadius: 2,
              background: 'rgba(255,255,255,0.1)',
              overflow: 'hidden',
            }}
          >
            <div
              style={{
                height: '100%',
                width: `${Math.min(spendPct, 100)}%`,
                background: 'var(--accent)',
                borderRadius: 2,
                transition: 'width 0.6s ease',
              }}
            />
          </div>
        </div>

        {/* Action buttons */}
        <div style={{ display: 'flex', gap: 12 }}>
          {/* Skip anyway */}
          <button
            type="button"
            onClick={onSkip}
            style={{
              flex: 1,
              height: 48,
              borderRadius: 14,
              background: 'rgba(255,255,255,0.07)',
              border: '1px solid rgba(255,255,255,0.15)',
              color: 'var(--text-muted)',
              fontSize: 14,
              fontWeight: 400,
            }}
          >
            skip anyway
          </button>

          {/* I'll wait */}
          <button
            type="button"
            onClick={handlePause}
            style={{
              flex: 1,
              height: 48,
              borderRadius: 14,
              background: flashing ? '#4ECCA3' : 'var(--accent)',
              color: '#050D1A',
              fontSize: 14,
              fontWeight: 500,
              transition: 'background 0.2s ease',
              border: 'none',
            }}
          >
            i'll wait ✓
          </button>
        </div>
      </div>
    </>
  );
}
